import React, { useEffect, useState } from 'react';
import ReactDOM from 'react-dom/client';

function App() {
  const [products, setProducts] = useState([]);

  useEffect(() => {
    // This part talks to your Backend on Port 3000!
    fetch('http://localhost:3000/api/products')
      .then(res => res.json())
      .then(data => setProducts(data))
      .catch(err => console.error("Database not connected:", err));
  }, []);

  return (
    <div style={{ fontFamily: 'Arial', padding: '20px', textAlign: 'center' }}>
      <h1 style={{ color: '#2c3e50' }}>🛍️ ShopHub Storefront</h1>
      <hr />
      <div style={{ display: 'flex', justifyContent: 'center', gap: '20px', flexWrap: 'wrap' }}>
        {products.map(product => (
          <div key={product.id} style={{ border: '1px solid #ddd', padding: '15px', borderRadius: '8px', width: '200px' }}>
            <h3>{product.name}</h3>
            <p style={{ fontWeight: 'bold', color: '#27ae60' }}>${product.price}</p>
            <button style={{ background: '#3498db', color: 'white', border: 'none', padding: '10px', borderRadius: '5px' }}>
              Add to Cart
            </button>
          </div>
        ))}
      </div>
    </div>
  );
}

const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(<App />);
